#!run
import {sessionInfo} from "@acepad/sessions";
import {getTS} from "./runts.js";
export function main(){
  const sh=this;
  this.$acepad.getMainEditor().
    on("changeSession", (e)=>{
      const si=sessionInfo(e.session);
      if(si.file&&
      si.file.ext()===".ts"){
        const c=sh.clone();
        c.cd(si.file.up());
        c.tscworker();
      }
      if(si.file&&
      si.file.ext()===".js"){
        const tsf=getTS(si.file.path());
        console.log("tsf",tsf);
        if(sh.resolve(tsf).exists()){
          if(confirm(`switch to ts?`)){
            sh.edit(tsf);
          }
        }
      }
    });
}